{
var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
    new PixelBuffer(context.TileSize, context.TileSize);
var mode = GetChoice(parameters, "mirrorMode", "quadrant");
var blend = GetFloat(parameters, "blendOverlap", 0f);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var halfW = size / 2;
var halfH = size / 2;
var quarterW = size / 4;
var quarterH = size / 4;

buffer.ParallelForEachPixel((x, y) =>
{
    float sx, sy;

    switch (mode)
    {
        case "horizontal":
            sx = x < halfW ? x : size - 1 - x;
            sy = y;
            break;

        case "vertical":
            sx = x;
            sy = y < halfH ? y : size - 1 - y;
            break;

        case "eighth":
            // Mirror both axes then mirror the quadrant
            sx = x < halfW ? x : size - 1 - x;
            sy = y < halfH ? y : size - 1 - y;
            // Mirror diagonal within the quadrant
            if (sx < sy)
            {
                (sx, sy) = (sy, sx);
            }
            sx = Math.Clamp(sx, 0, size - 1);
            sy = Math.Clamp(sy, 0, size - 1);
            break;

        case "checkerboard":
        {
            var cellX = x / quarterW;
            var cellY = y / quarterH;
            var localX = x % quarterW;
            var localY = y % quarterH;
            if ((cellX + cellY) % 2 == 1)
            {
                sx = (cellX % 2 == 0 ? quarterW - 1 - localX : localX);
                sy = (cellY % 2 == 0 ? quarterH - 1 - localY : localY);
                sx += cellX * quarterW;
                sy += cellY * quarterH;
            }
            else
            {
                sx = x;
                sy = y;
            }
            break;
        }

        default: // quadrant
        {
            // Mirror X and Y
            var mx = x < halfW ? x : size - 1 - x;
            var my = y < halfH ? y : size - 1 - y;
            // Remap to the corresponding quadrant
            var qx = x < halfW ? 0 : 1;
            var qy = y < halfH ? 0 : 1;
            sx = qx == 0 ? mx : size - 1 - mx;
            sy = qy == 0 ? my : size - 1 - my;
            break;
        }
    }

    sx = Math.Clamp(sx, 0, size - 1);
    sy = Math.Clamp(sy, 0, size - 1);

    var (r, g, b, a) = input.GetPixel((int)sx, (int)sy);

    // Blend at mirror seams for smoothness
    if (blend > 0f)
    {
        var dx = MathF.Abs(x - sx) / (float)size;
        var dy = MathF.Abs(y - sy) / (float)size;
        var seamDist = MathF.Max(dx, dy);
        if (seamDist < blend * 0.2f)
        {
            var (origR, origG, origB, origA) = input.GetPixel(x, y);
            var t = seamDist / (blend * 0.2f);
            r = Lerp(r, origR, t);
            g = Lerp(g, origG, t);
            b = Lerp(b, origB, t);
            a = Lerp(a, origA, t);
        }
    }

    buffer.SetPixel(x, y, r, g, b, a);
});

return buffer;
}
